EXAMPLE.good:
// ✅ Correct: Memoized callbacks and values
const MemoizedComponent = ({ items, onItemClick }) => {
  const sortedItems = useMemo(
    () => [...items].sort((a, b) => a.name.localeCompare(b.name)),
    [items]
  );

  const handleClick = useCallback(
    (id: string) => {
      onItemClick(id);
    },
    [onItemClick]
  );

  return <ItemList items={sortedItems} onClick={handleClick} />;
};

EXAMPLE.bad:
// ❌ Wrong: Unnecessary re-renders
const Component = ({ items, onItemClick }) => {
  // Recreated every render - causes ItemList re-render
  const sortedItems = [...items].sort((a, b) => a.name.localeCompare(b.name));

  // New function every render - breaks React.memo children
  const handleClick = (id) => onItemClick(id);

  return <ItemList items={sortedItems} onClick={handleClick} />;
};
